    // This is a corner or junction in a 2-cell-wide road

    // Simple corners: exactly 2 orthogonal neighbors (no parallel row/column)
    if (hCount == 1 && vCount == 1)
    {
        if (up && right) return pathCornerBottomLeft;
        if (up && left) return pathCornerBottomRight;
        if (down && right) return pathCornerTopLeft;
        if (down && left) return pathCornerTopRight;
    }

    // Junction cells (3-4 neighbors): use diagonal analysis
    // At a 2-cell-wide road junction, the diagonal OPPOSITE to the
    // "empty" corner is also a path cell. We find which diagonal
    // is NOT path to determine the corner type.
    //
    // Corner naming: the corner tile has grass in the named quadrant
    //   转弯左下 (CLb): grass bottom-left → road goes UP and RIGHT
    //   转弯右下 (CRb): grass bottom-right → road goes UP and LEFT
    //   转弯左上 (CLt): grass top-left → road goes DOWN and RIGHT
    //   转弯右上 (CRt): grass top-right → road goes DOWN and LEFT

    // Find which quadrant has NO road (the "empty" corner = grass side)
    // If diagonal is NOT path, that's where the grass corner should be
    if (!downRight && upLeft) return pathCornerBottomRight;  // grass bottom-right → CRb
    if (!downLeft && upRight) return pathCornerBottomLeft;   // grass bottom-left → CLb
    if (!upRight && downLeft) return pathCornerTopRight;     // grass top-right → CRt
    if (!upLeft && downRight) return pathCornerTopLeft;      // grass top-left → CLt

    // If diagonals can't determine (all or none), fall back to edge analysis
    // Use which half of the road this cell is on
    if (left && right)
    {
        // Part of a horizontal road with vertical connection
        if (up && !down) return pathHorizontalBottom;
        if (down && !up) return pathHorizontalTop;
        // Both up and down - determine half from perpendicular neighbor
        if (upRight || downRight) return pathHorizontalBottom;
        if (upLeft || downLeft) return pathHorizontalTop;
        return pathHorizontalTop;
    }

    if (up && down)
    {
        // Part of a vertical road with horizontal connection
        if (left && !right) return pathVerticalRight;
        if (right && !left) return pathVerticalLeft;
        if (upLeft || downLeft) return pathVerticalRight;
        if (upRight || downRight) return pathVerticalLeft;
        return pathVerticalLeft;
    }

    // Single tile (start/end)
    return pathTile;
}

