private TileBase SelectPathTile(Vector3Int cell, HashSet<Vector3Int> pathCells)
{
    bool up = pathCells.Contains(cell + Vector3Int.up);
    bool down = pathCells.Contains(cell + Vector3Int.down);
    bool left = pathCells.Contains(cell + Vector3Int.left);
    bool right = pathCells.Contains(cell + Vector3Int.right);

    // Diagonal neighbors - used to distinguish parallel rows from junctions
    bool upLeft = pathCells.Contains(cell + Vector3Int.up + Vector3Int.left);
    bool upRight = pathCells.Contains(cell + Vector3Int.up + Vector3Int.right);
    bool downLeft = pathCells.Contains(cell + Vector3Int.down + Vector3Int.left);
    bool downRight = pathCells.Contains(cell + Vector3Int.down + Vector3Int.right);

    // In a 2-cell-wide road, perpendicular neighbors can be:
    //   a) A parallel row/column (same road) - extends in the same direction
    //   b) A junction (different road) - extends in a perpendicular direction
    // We detect parallel rows by checking if the perpendicular neighbor
    // also extends in the road's primary direction (via diagonals).

    // --- Horizontal road analysis ---
    // A cell is primarily in a horizontal road if it has both left+right neighbors
    bool isHorizontal = left && right;

    // A cell is primarily in a vertical road if it has both up+down neighbors
    bool isVertical = up && down;

    if (isHorizontal)
    {
        // This cell is part of a horizontal road segment
        // Determine which half (top or bottom row)
        // Check if the perpendicular neighbor is a parallel row or a junction
        bool upIsParallel = up && upLeft && upRight;
        bool downIsParallel = down && downLeft && downRight;

        if (up && !down)
        {
            // Only up neighbor - is it parallel row or junction?
            if (upIsParallel)
                return pathHorizontalBottom; // Parallel row above → this is bottom
            else
                return pathCornerTopLeft; // Junction - road turns up (will be refined below)
        }
        if (down && !up)
        {
            if (downIsParallel)
                return pathHorizontalTop; // Parallel row below → this is top
            else
                return pathCornerBottomLeft; // Junction - road turns down
        }
        if (up && down)
        {
            // Both up and down neighbors
            bool upJunction = up && !upIsParallel;
            bool downJunction = down && !downIsParallel;

            if (upJunction && !downJunction)
                return pathHorizontalBottom; // Up is junction, this is bottom half
            if (downJunction && !upJunction)
                return pathHorizontalTop; // Down is junction, this is top half

            // Both parallel or both junction - use diagonal to determine corner
            if (!downRight && upLeft) return pathCornerBottomRight;
            if (!downLeft && upRight) return pathCornerBottomLeft;
            if (!upRight && downLeft) return pathCornerTopRight;
            if (!upLeft && downRight) return pathCornerTopLeft;

            // Fallback: use relative position
            return pathHorizontalTop;
        }
        // No perpendicular neighbors - pure horizontal
        // Determine half by checking if there's a parallel row
        return pathHorizontalTop;
    }

    if (isVertical)
    {
        // This cell is part of a vertical road segment
        bool leftIsParallel = left && upLeft && downLeft;
        bool rightIsParallel = right && upRight && downRight;

        if (left && !right)
        {
            if (leftIsParallel)
                return pathVerticalRight; // Parallel column to left → this is right
            else
                return pathCornerTopRight; // Junction
        }
        if (right && !left)
        {
            if (rightIsParallel)
                return pathVerticalLeft; // Parallel column to right → this is left
            else
                return pathCornerTopLeft; // Junction
        }
        if (left && right)
        {
            bool leftJunction = left && !leftIsParallel;
            bool rightJunction = right && !rightIsParallel;

            if (leftJunction && !rightJunction)
                return pathVerticalRight;
            if (rightJunction && !leftJunction)
                return pathVerticalLeft;

            // Both parallel or both junction - use diagonal for corner
            if (!downRight && upLeft) return pathCornerBottomRight;
            if (!downLeft && upRight) return pathCornerBottomLeft;
            if (!upRight && downLeft) return pathCornerTopRight;
            if (!upLeft && downRight) return pathCornerTopLeft;

            return pathVerticalLeft;
        }
        return pathVerticalLeft;
    }

    // --- Simple corners: exactly 2 orthogonal neighbors ---
    if (up && right && !down && !left) return pathCornerBottomLeft;
    if (up && left && !down && !right) return pathCornerBottomRight;
    if (down && right && !up && !left) return pathCornerTopLeft;
    if (down && left && !up && !right) return pathCornerTopRight;

    // --- Single-neighbor cells (endpoints or edges) ---
    if (left || right) return up ? pathHorizontalBottom : pathHorizontalTop;
    if (up || down) return right ? pathVerticalLeft : pathVerticalRight;

    // Single tile (isolated)
    return pathTile;
}

