var lb = UnityEngine.Object.FindObjectOfType<TowerDefense.Map.LevelBuilder>();
var guids = UnityEditor.AssetDatabase.FindAssets("t:LevelData");
var ld = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>(UnityEditor.AssetDatabase.GUIDToAssetPath(guids[0]));
lb.BuildLevel(ld);

// Check tile counts
var so = new UnityEditor.SerializedObject(lb);
var pathMap = so.FindProperty("pathMap").objectReferenceValue as UnityEngine.Tilemaps.Tilemap;
var bounds = pathMap.cellBounds;
var tileCounts = new System.Collections.Generic.Dictionary<string, int>();
var problemTiles = new System.Collections.Generic.List<string>();

for (int x = bounds.xMin; x < bounds.xMax; x++)
{
    for (int y = bounds.yMin; y < bounds.yMax; y++)
    {
        var cell = new UnityEngine.Vector3Int(x, y, 0);
        var tile = pathMap.GetTile(cell);
        if (tile != null)
        {
            string name = tile.name;
            if (!tileCounts.ContainsKey(name)) tileCounts[name] = 0;
            tileCounts[name]++;
            if (name == "PathTile 3" || name == "GrassTile")
                problemTiles.Add($"[{x},{y}] = {name}");
        }
    }
}

UnityEngine.Debug.Log("Tile counts after rebuild:");
foreach (var kv in tileCounts)
    UnityEngine.Debug.Log($"  {kv.Key}: {kv.Value}");
UnityEngine.Debug.Log($"Problem tiles: {problemTiles.Count}");

// Print the path tilemap visualization
var lb = UnityEngine.Object.FindObjectOfType<TowerDefense.Map.LevelBuilder>();
var so = new UnityEditor.SerializedObject(lb);
var pathMap = so.FindProperty("pathMap").objectReferenceValue as UnityEngine.Tilemaps.Tilemap;

int minX = 1, maxX = 28, minY = 1, maxY = 17;
var sb = new System.Text.StringBuilder();
sb.AppendLine("Path Tilemap:");
for (int y = maxY; y >= minY; y--)
{
    sb.Append($"{y,3} ");
    for (int x = minX; x <= maxX; x++)
    {
        var tile = pathMap.GetTile(new UnityEngine.Vector3Int(x, y, 0));
        if (tile == null) sb.Append(" . ");
        else
        {
            string n = tile.name;
            if (n == "横上") sb.Append("Ht");
            else if (n == "横下") sb.Append("Hb");
            else if (n == "竖左") sb.Append("Vl");
            else if (n == "竖右") sb.Append("Vr");
            else if (n.Contains("转弯")) sb.Append(n.Replace("转弯","C"));
            else sb.Append($"??");
        }
        sb.Append(" ");
    }
    sb.AppendLine();
}
UnityEngine.Debug.Log(sb.ToString());

