namespace TowerDefense.Tower
{
    /// <summary>
    /// 塔槽位组件 - 管理塔的放置、移除、升级和售卖
    /// </summary>
    public class TowerSlot : MonoBehaviour
    {
        [Header("Slot Settings")]
        [Tooltip("是否已被占用")]
        [SerializeField] private bool _isOccupied = false;

        [Tooltip("当前塔实例")]
        [SerializeField] private Tower _currentTower;

        [Tooltip("高亮效果物体")]
        [SerializeField] private GameObject _highlight;

        [Tooltip("建造指示器")]
        [SerializeField] private GameObject _buildIndicator;

        [Header("Slot Type")]
        [Tooltip("槽位类型")]
        [SerializeField] private LevelData.SlotType _slotType = LevelData.SlotType.Normal;

        [Header("Spawn Settings")]
        [Tooltip("塔的Z轴位置")]
        [SerializeField] private float _towerZPosition = -1f;

        [Tooltip("塔的缩放")]
        [SerializeField] private Vector3 _towerScale = Vector3.one;

        [Header("Build Button Settings")]
        [Tooltip("可以建造的塔列表")]
        [SerializeField] private TowerData[] buildableTowers;

        [Header("Events")]
        [Tooltip("塔放置事件")]
        public UnityEvent OnTowerPlaced;

        [Tooltip("塔移除事件")]
        [SerializeField] private UnityEvent OnTowerRemoved;

        [Tooltip("槽位选中事件")]
        public UnityEvent OnSlotSelected;

        /// <summary>
        /// 是否已被占用
        /// </summary>
        public bool IsOccupied => _isOccupied;

        /// <summary>
        /// 当前塔实例
        /// </summary>
        public Tower CurrentTower => _currentTower;

        /// <summary>
        /// 槽位类型
        /// </summary>
        public LevelData.SlotType SlotType => _slotType;

        /// <summary>
        /// 是否处于悬停状态
        /// </summary>
        private bool _isHovered = false;

        /// <summary>
        /// 是否处于选中状态
        /// </summary>
        private bool _isSelected = false;

        /// <summary>
        /// 初始化组件
        /// </summary>
        private void Awake()
        {
           // Debug.Log($"TowerSlot {gameObject.name} initialized");

            // 初始化高亮和建造指示器状态
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(!_isOccupied);
            }
        }

        /// <summary>
        /// 鼠标进入槽位
        /// </summary>
        private void OnMouseEnter()
        {
            if (!_isOccupied)
            {
                _isHovered = true;
                // Debug.Log($"Mouse entered slot: {gameObject.name}");

                // 显示高亮效果
                if (_highlight != null)
                {
                    _highlight.SetActive(true);
                }
            }
        }

        /// <summary>
        /// 鼠标离开槽位
        /// </summary>
        private void OnMouseExit()
        {
            _isHovered = false;
            // 非选中状态下隐藏高亮
            if (_highlight != null && !_isSelected)
            {
                _highlight.SetActive(false);
            }
        }

        /// <summary>
        /// 鼠标点击槽位
        /// </summary>
        private void OnMouseDown()
        {
            Debug.Log($"Slot clicked: {gameObject.name}, IsOccupied: {_isOccupied}");

            // 关闭其他面板
            HideAllPanels();

            if (!_isOccupied)
            {
                SelectSlot();
                ShowTowerSelectPanel();
            }
            else
            {
                SelectSlot();
                ShowTowerInfoPanel();
            }
        }

        /// <summary>
        /// 选中槽位
        /// </summary>
        public void SelectSlot()
        {
            _isSelected = true;
            OnSlotSelected?.Invoke();
                // Debug.Log($"Slot selected: {gameObject.name}");

            // 如果有塔，显示攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.ShowRange();
            }
        }

        /// <summary>
        /// 取消选中槽位
        /// </summary>
        public void DeselectSlot()
        {
            _isSelected = false;
            // 隐藏高亮效果
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 如果有塔，隐藏攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.HideRange();
            }
                // Debug.Log($"Slot deselected: {gameObject.name}");
        }

        /// <summary>
        /// 显示塔选择面板
        /// </summary>
        private void ShowTowerSelectPanel()
        {
            // 先尝试通过 画布 下已知路径查找（包括非激活对象）
            TowerSelectPanel panel = null;
            var panelObj = GameObject.Find("画布/塔选择面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：用英文名查找（兼容重命名前）
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerSelectPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：在激活对象中查找
            if (panel == null)
            {
                panel = FindObjectOfType<TowerSelectPanel>();
            }

            if (panel != null)
            {
                panel.Show(this);
            }
        }

        /// <summary>
        /// 显示塔信息面板
        /// </summary>
        private void ShowTowerInfoPanel()
        {
            TowerInfoPanel panel = null;
            var panelObj = GameObject.Find("画布/塔信息面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerInfoPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panel = FindObjectOfType<TowerInfoPanel>();
            }
            if (panel != null && _currentTower != null)
            {
                panel.Show(_currentTower);
            }
        }

        /// <summary>
        /// 隐藏所有UI面板
        /// </summary>
        private void HideAllPanels()
        {
            var selectObj = GameObject.Find("画布/塔选择面板");
            if (selectObj == null) selectObj = GameObject.Find("Canvas/TowerSelectPanel");
            if (selectObj != null)
            {
                var selectPanel = selectObj.GetComponent<TowerSelectPanel>();
                if (selectPanel != null) selectPanel.Hide();
            }
            else
            {
                var sp = FindObjectOfType<TowerSelectPanel>();
                if (sp != null) sp.Hide();
            }

            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }

            if (BuildButtonManager.Instance != null)
            {
                BuildButtonManager.Instance.HideBuildButton();
            }
        }

        /// <summary>
        /// 被管理器调用的建造按钮点击
        /// </summary>
        public void OnBuildButtonClickedByManager()
        {
                // Debug.Log("OnBuildButtonClickedByManager called!");

            // 尝试放置塔
            TowerData towerToBuild = GetTowerDataToBuild();

            if (towerToBuild != null)
            {
                bool success = PlaceTower(towerToBuild);

                if (success)
                {
                    // Debug.Log("✅ Tower built successfully!");
                }
                else
                {
                    // Debug.Log("❌ Failed to build tower!");
                }
            }
            else
            {
                // Debug.LogError("❌ No tower data to build!");
            }
        }

        /// <summary>
        /// 获取要建造的塔数据
        /// </summary>
        private TowerData GetTowerDataToBuild()
        {
            // 优先使用配置的塔列表
            if (buildableTowers != null && buildableTowers.Length > 0)
            {
                    // Debug.Log($"Using configured tower: {buildableTowers[0].towerName}");
                return buildableTowers[0];
            }

            // 尝试从Resources/Data/Towers/加载
            Debug.Log("Trying to load from Resources/Data/Towers/");
            TowerData[] towerDatas1 = Resources.LoadAll<TowerData>("Data/Towers");
            if (towerDatas1.Length > 0)
            {
                     Debug.Log($"Found {towerDatas1.Length} tower data assets in Data/Towers/");
                return towerDatas1[0];
            }

            // 尝试从Resources/Data/加载
            Debug.Log("Trying to load from Resources/Data/");
            TowerData[] towerDatas2 = Resources.LoadAll<TowerData>("Data");
            if (towerDatas2.Length > 0)
            {
                Debug.Log($"Found {towerDatas2.Length} tower data assets in Data/");
                return towerDatas2[0];
            }

                Debug.LogError("❌ No tower data found!");
            return null;
        }

        /// <summary>
        /// 在槽位放置塔
        /// </summary>
        /// <param name="towerData">塔数据</param>
        /// <returns>是否放置成功</returns>
        public bool PlaceTower(TowerData towerData)
        {
            // 检查是否已被占用
            if (_isOccupied) return false;

            // 检查金币是否足够
            if (!GameManager.Instance.SpendGold(towerData.levels[0].cost))
            {
                Debug.Log("❌ Not enough gold!");
                return false;
            }

            // 设置生成位置（调整Z轴和缩放）
            Vector3 spawnPos = transform.position;
            spawnPos.z = _towerZPosition;

            // 实例化塔
            GameObject towerObj = Instantiate(towerData.towerPrefab, spawnPos, Quaternion.identity);

            // 应用缩放
            if (_towerScale != Vector3.one)
            {
                towerObj.transform.localScale = _towerScale;
            }

            _currentTower = towerObj.GetComponent<Tower>();

            // 初始化塔
            if (_currentTower != null)
            {
                _currentTower.Initialize(towerData, this);
            }

            // 更新状态
            _isOccupied = true;

            // 更新UI显示
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(false);
            }
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 触发事件
            OnTowerPlaced?.Invoke();
            EventBus.Publish(new TowerPlacedEvent { Tower = towerObj, Cost = towerData.levels[0].cost });

            return true;
        }

        /// <summary>
        /// 移除塔（不返还金币）
        /// </summary>
        public void RemoveTower()
        {
            _currentTower = null;
            _isOccupied = false;

            // 显示建造指示器
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(true);
            }

            OnTowerRemoved?.Invoke();
        }

        /// <summary>
        /// 售卖塔（返还部分金币）
        /// </summary>
        public void SellTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Sell();
        }

        /// <summary>
        /// 升级塔
        /// </summary>
        public void UpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Upgrade();
        }

        /// <summary>
        /// 获取塔的售卖价值
        /// </summary>
        /// <returns>售卖金币数</returns>
        public int GetTowerSellValue()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetSellValue();
        }

        /// <summary>
        /// 获取塔的升级费用
        /// </summary>
        /// <returns>升级金币数</returns>
        public int GetTowerUpgradeCost()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetUpgradeCost();
        }

        /// <summary>
        /// 检查塔是否可以升级
        /// </summary>
        /// <returns>是否可升级</returns>
        public bool CanUpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return false;
            return !_currentTower.IsMaxLevel;
        }

        /// <summary>
        /// 绘制Gizmos（编辑器模式下）
        /// </summary>
        private void OnDrawGizmos()
        {
            // 绿色表示可建造，红色表示已占用
            Gizmos.color = _isOccupied ? Color.red : Color.green;
            Gizmos.DrawWireSphere(transform.position, 0.3f);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Tower;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerSelectPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;
        [SerializeField] private Text _slotInfoText;

        [Header("Text Settings")]
        [SerializeField] private Font _buttonFont;


        [Header("Tower Data")]
        [SerializeField] private TowerData[] _availableTowers;

        private TowerSlot _currentSlot;
        private TowerData[] _towerDatas;

        private void Awake()
        {
            Debug.Log($"TowerSelectPanel Awake - _panel: {_panel != null}, _container: {_towerButtonContainer != null}, _prefab: {_towerButtonPrefab != null}, _text: {_slotInfoText != null}");

            if (_panel != null)
            {
                _panel.SetActive(false);
            }

            LoadTowerData();
        }

        private void LoadTowerData()
        {
            if (_availableTowers != null && _availableTowers.Length > 0)
            {
                _towerDatas = _availableTowers;
            }
            else
            {
                _towerDatas = Resources.LoadAll<TowerData>("Data");
            }
        }

        public void Show(TowerSlot slot)
        {
            Debug.Log($"TowerSelectPanel.Show() called - _panel: {_panel != null}, _towerDatas length: {_towerDatas?.Length ?? 0}");

            _currentSlot = slot;

            if (_panel == null)
            {
                CreateSimplePanel();
            }

            if (_slotInfoText != null)
            {
                _slotInfoText.text = "选择要建造的塔";
            }

            RefreshTowerButtons();

            if (_panel != null)
            {
                _panel.SetActive(true);
                Debug.Log("✅ TowerSelectPanel 已显示");
            }
            else
            {
                Debug.LogWarning("⚠️ TowerSelectPanel 的 _panel 字段未设置！请在 Inspector 中设置。");
            }
        }

        private void CreateSimplePanel()
        {
            Debug.Log("📦 自动创建简单的塔选择面板...");

            Canvas canvas = FindObjectOfType<Canvas>();
            if (canvas == null)
            {
                Debug.LogError("❌ 找不到 Canvas！");
                return;
            }

            GameObject panelObj = new GameObject("TowerSelectPanel_Content");
            panelObj.transform.SetParent(canvas.transform, false);

            Image panelImage = panelObj.AddComponent<Image>();
            panelImage.color = new Color(0.2f, 0.2f, 0.2f, 0.95f);

            RectTransform rect = panelObj.GetComponent<RectTransform>();
            rect.sizeDelta = new Vector2(300, 400);
            rect.anchorMin = new Vector2(0.5f, 0.5f);
            rect.anchorMax = new Vector2(0.5f, 0.5f);
            rect.pivot = new Vector2(0.5f, 0.5f);
            rect.anchoredPosition = Vector2.zero;

            GameObject titleObj = new GameObject("Title");
            titleObj.transform.SetParent(panelObj.transform, false);
            Text titleText = titleObj.AddComponent<Text>();
            titleText.text = "选择要建造的塔";
            titleText.fontSize = 24;
            titleText.alignment = TextAnchor.MiddleCenter;
            _slotInfoText = titleText;

            RectTransform titleRect = titleObj.GetComponent<RectTransform>();
            titleRect.sizeDelta = new Vector2(280, 40);
            titleRect.anchorMin = new Vector2(0.5f, 1);
            titleRect.anchorMax = new Vector2(0.5f, 1);
            titleRect.pivot = new Vector2(0.5f, 1);
            titleRect.anchoredPosition = new Vector2(0, -20);

            GameObject containerObj = new GameObject("TowerButtonContainer");
            containerObj.transform.SetParent(panelObj.transform, false);

            RectTransform containerRect = containerObj.GetComponent<RectTransform>();
            containerRect.sizeDelta = new Vector2(260, 300);
            containerRect.anchorMin = new Vector2(0.5f, 0);
            containerRect.anchorMax = new Vector2(0.5f, 1);
            containerRect.pivot = new Vector2(0.5f, 0.5f);
            containerRect.anchoredPosition = new Vector2(0, -20);

            VerticalLayoutGroup layout = containerObj.AddComponent<VerticalLayoutGroup>();
            layout.padding = new RectOffset(10, 10, 10, 10);
            layout.spacing = 10;
            layout.childAlignment = TextAnchor.UpperCenter;

            _towerButtonContainer = containerRect;

            GameObject closeBtnObj = new GameObject("CloseButton");
            closeBtnObj.transform.SetParent(panelObj.transform, false);

            Button closeBtn = closeBtnObj.AddComponent<Button>();
            closeBtn.onClick.AddListener(Hide);

            Image closeImage = closeBtnObj.AddComponent<Image>();
            closeImage.color = new Color(0.6f, 0.2f, 0.2f);

            Text closeText = closeBtnObj.AddComponent<Text>();
            closeText.text = "关闭";
            closeText.alignment = TextAnchor.MiddleCenter;

            RectTransform closeRect = closeBtnObj.GetComponent<RectTransform>();
            closeRect.sizeDelta = new Vector2(200, 40);
            closeRect.anchorMin = new Vector2(0.5f, 0);
            closeRect.anchorMax = new Vector2(0.5f, 0);
            closeRect.pivot = new Vector2(0.5f, 0);
            closeRect.anchoredPosition = new Vector2(0, 20);

            _panel = panelObj;
            _panel.SetActive(false);

            Debug.Log("✅ 简单塔选择面板创建完成");
        }

        public void Hide()
        {
            _currentSlot = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void RefreshTowerButtons()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                Destroy(child.gameObject);
            }

            foreach (var towerData in _towerDatas)
            {
                CreateTowerButton(towerData);
            }
        }

        private void CreateTowerButton(TowerData towerData)
        {
            Debug.Log($"🆕 创建塔按钮: {towerData.towerName}, icon? {(towerData.icon != null ? "✅ 设置了" + towerData.icon.name : "❌ 空")}");

            GameObject buttonObj;

            if (_towerButtonPrefab == null)
            {
                buttonObj = new GameObject($"TowerButton_{towerData.towerName}");
                buttonObj.transform.SetParent(_towerButtonContainer, false);

                Button button = buttonObj.AddComponent<Button>();
                Image bgImage = buttonObj.AddComponent<Image>();
                bgImage.color = new Color(0.4f, 0.4f, 0.6f);

                RectTransform buttonRect = buttonObj.GetComponent<RectTransform>();
                buttonRect.sizeDelta = new Vector2(70, 85);

                if (towerData.icon != null)
                {
                    Debug.Log($"✅ 找到塔图标: {towerData.towerName} -> {towerData.icon.name}");

                    GameObject iconObj = new GameObject("Icon");
                    iconObj.transform.SetParent(buttonObj.transform, false);

                    Image iconImage = iconObj.AddComponent<Image>();
                    iconImage.sprite = towerData.icon;
                    iconImage.preserveAspect = true;

                    RectTransform iconRect = iconObj.GetComponent<RectTransform>();
                    iconRect.anchorMin = new Vector2(0.5f, 0.4f);
                    iconRect.anchorMax = new Vector2(0.5f, 1f);
                    iconRect.offsetMin = new Vector2(-30, 0);
                    iconRect.offsetMax = new Vector2(30, 0);
                }
                else
                {
                    Debug.LogWarning($"❌ 没有找到塔图标: {towerData.towerName}");
                }

                GameObject textObj = new GameObject("Text");
                textObj.transform.SetParent(buttonObj.transform, false);

                Outline outline = textObj.AddComponent<Outline>();
                outline.effectColor = Color.black;
                outline.effectDistance = new Vector2(2, -2);

                Text text = textObj.AddComponent<Text>();
                text.text = $"{GetTowerPrice(towerData)}";

                if (_buttonFont != null)
                {
                    text.font = _buttonFont;
                }

                text.fontSize = 26;
                text.fontStyle = FontStyle.Bold;
                text.alignment = TextAnchor.LowerCenter;
                text.color = new Color(1f, 0.9f, 0f);
                text.horizontalOverflow = HorizontalWrapMode.Overflow;
                text.verticalOverflow = VerticalWrapMode.Overflow;

                RectTransform textRect = textObj.GetComponent<RectTransform>();
                textRect.anchorMin = Vector2.zero;
                textRect.anchorMax = new Vector2(1f, 0.35f);
                textRect.offsetMin = Vector2.zero;
                textRect.offsetMax = Vector2.zero;

                bool canAfford = GameManager.Instance.HasEnoughGold(GetTowerPrice(towerData));
                button.interactable = canAfford;
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                if (!canAfford)
                {
                    bgImage.color = new Color(0.3f, 0.3f, 0.3f);
                }
            }
            else
            {
                buttonObj = Instantiate(_towerButtonPrefab, _towerButtonContainer);
                buttonObj.name = $"TowerButton_{towerData.towerName}";

                TowerButton button = buttonObj.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.Initialize(towerData, this);
                }
                else
                {
                    SetupButtonManually(buttonObj, towerData);
                }
            }
        }

        private int GetTowerPrice(TowerData towerData)
        {
            if (towerData.levels != null && towerData.levels.Length > 0)
            {
                return towerData.levels[0].cost;
            }
            return 0;
        }

        private void SetupButtonManually(GameObject buttonObj, TowerData towerData)
        {
            Text nameText = buttonObj.GetComponentInChildren<Text>();
            if (nameText != null)
            {
                nameText.text = towerData.towerName;
            }

            Image[] images = buttonObj.GetComponentsInChildren<Image>();
            foreach (var img in images)
            {
                if (img.gameObject != buttonObj && towerData.icon != null && img.sprite == null)
                {
                    img.sprite = towerData.icon;
                    img.preserveAspect = true;
                    break;
                }
            }

            Button button = buttonObj.GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                bool canAfford = GameManager.Instance.HasEnoughGold(towerData.levels[0].cost);
                button.interactable = canAfford;
            }
        }

        public void OnTowerSelected(TowerData towerData)
        {
            if (_currentSlot != null)
            {
                bool success = _currentSlot.PlaceTower(towerData);
                if (success)
                {
                    Hide();
                }
            }
        }

        public void UpdateButtonStates()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                TowerButton button = child.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.UpdateState();
                }
            }
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateButtonStates();
        }
    }

    public class TowerButton : MonoBehaviour
    {
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _costText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Image _icon;

        private TowerData _towerData;
        private TowerSelectPanel _panel;

        public void Initialize(TowerData towerData, TowerSelectPanel panel)
        {
            _towerData = towerData;
            _panel = panel;

            if (_nameText != null)
            {
                _nameText.text = towerData.towerName;
            }

            TowerData.TowerStats stats = towerData.levels[0];
            if (_costText != null)
            {
                _costText.text = $"{stats.cost} G";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"范围: {stats.attackRange}";
            }

            if (towerData.icon != null)
            {
                Debug.Log($"✅ TowerButton 找到塔图标: {towerData.towerName} -> {towerData.icon.name}");

                if (_icon != null)
                {
                    _icon.sprite = towerData.icon;
                    _icon.gameObject.SetActive(true);
                }

                Image[] allImages = GetComponentsInChildren<Image>();
                foreach (var img in allImages)
                {
                    if (img.gameObject != gameObject && img.sprite == null)
                    {
                        img.sprite = towerData.icon;
                        img.preserveAspect = true;
                        Debug.Log($"✅ 自动填充图标到 Image: {img.gameObject.name}");
                        break;
                    }
                }
            }
            else
            {
                Debug.LogWarning($"❌ TowerButton 没有塔图标: {towerData.towerName}");

                if (_icon != null)
                {
                    _icon.gameObject.SetActive(false);
                }
            }

            UpdateState();

            Button button = GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(OnClicked);
            }
        }

        public void UpdateState()
        {
            Button button = GetComponent<Button>();
            if (button != null)
            {
                bool canAfford = GameManager.Instance.HasEnoughGold(_towerData.levels[0].cost);
                button.interactable = canAfford;

                Image image = GetComponent<Image>();
                if (image != null)
                {
                    image.color = canAfford ? Color.white : Color.grey;
                }
            }
        }

        private void OnClicked()
        {
            if (_panel != null)
            {
                _panel.OnTowerSelected(_towerData);
            }
        }
    }
}

