// Check TowerSlot objects - do they have colliders? OnMouseDown needs a collider to work.
var slots = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.TowerSlot>();
UnityEngine.Debug.Log($"Total TowerSlots found: {slots.Length}");

int noCollider = 0;
int noPrefab = 0;
int occupied = 0;
int noBuildableTowers = 0;

foreach (var slot in slots)
{
    var col = slot.GetComponent<Collider2D>();
    var col3d = slot.GetComponent<Collider>();
    bool hasCollider = (col != null || col3d != null);

    if (!hasCollider) noCollider++;
    if (slot.IsOccupied) occupied++;

    var so = new UnityEditor.SerializedObject(slot);
    var buildableProp = so.FindProperty("buildableTowers");
    if (buildableProp != null && buildableProp.arraySize == 0) noBuildableTowers++;

    // Check towerData on the slot
    var towerPrefabProp = so.FindProperty("buildableTowers");

    // Only log first 3 for details
    if (noCollider > 0 && noCollider <= 3)
    {
        UnityEngine.Debug.Log($"  Slot {slot.gameObject.name}: hasCollider={hasCollider}, pos={slot.transform.position}, occupied={slot.IsOccupied}");
    }
}

UnityEngine.Debug.Log($"No collider: {noCollider}, Occupied: {occupied}, No buildable towers: {noBuildableTowers}");

