// Find the TowerSelectPanel and check its current state
var tspObj = UnityEngine.GameObject.Find("画布/塔选择面板");
var tsp = tspObj.GetComponent<TowerDefense.UI.TowerSelectPanel>();

// Check the buttons
var container = tspObj.transform.Find("GameObject");
if (container == null)
{
    // Try to find by iterating children
