    {
        var child = tspObj.transform.GetChild(i);
        UnityEngine.Debug.Log($"Panel child: {child.name}, childCount={child.childCount}");

        // Check buttons inside container
        for (int j = 0; j < child.childCount; j++)
        {
            var btn = child.GetChild(j);
            var button = btn.GetComponent<UnityEngine.UI.Button>();
            var tb = btn.GetComponent<TowerDefense.UI.TowerButton>();
            UnityEngine.Debug.Log($"  Button: {btn.name}, interactable={button?.interactable}, TowerButton={tb != null}");
        }
    }
}

// Try to simulate placing tower directly
var slots = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.TowerSlot>();
foreach (var slot in slots)
{
