// Simulate: click a slot, then click the tower button
var slots = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.TowerSlot>();
var slot = slots[0]; // First unoccupied slot

UnityEngine.Debug.Log($"=== Simulating full tower placement flow ===");
UnityEngine.Debug.Log($"Slot: {slot.gameObject.name}, Gold: {TowerDefense.Core.GameManager.Instance.CurrentGold}");

// Step 1: Click slot (OnMouseDown)
slot.GetType().GetMethod("OnMouseDown", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance)?.Invoke(slot, null);

// Step 2: Find the TowerSelectPanel and simulate tower selection
var tspObj = UnityEngine.GameObject.Find("画布/塔选择面板");
if (tspObj != null)
{
    var tsp = tspObj.GetComponent<TowerDefense.UI.TowerSelectPanel>();
    UnityEngine.Debug.Log($"Panel active: {tspObj.activeSelf}");

    // Try to select the 箭塔 (cost=100, affordable)
    var towerDatas = UnityEngine.Resources.LoadAll<TowerDefense.Data.TowerData>("Data/Towers");
    foreach (var td in towerDatas)
    {
        UnityEngine.Debug.Log($"Tower: {td.towerName}, cost={td.levels[0].cost}, prefab={td.towerPrefab?.name ?? "NULL"}");
    }

    // Directly call OnTowerSelected
    var affordableTower = towerDatas.FirstOrDefault(t => t.levels[0].cost <= TowerDefense.Core.GameManager.Instance.CurrentGold);
    if (affordableTower != null)
    {
        UnityEngine.Debug.Log($"Selecting affordable tower: {affordableTower.towerName}");
        tsp.OnTowerSelected(affordableTower);
    }
    else
    {
        UnityEngine.Debug.Log("No affordable tower!");
    }
}
else
{
    UnityEngine.Debug.Log("Panel not found!");
}

// Check result
UnityEngine.Debug.Log($"Slot occupied: {slot.IsOccupied}, Gold after: {TowerDefense.Core.GameManager.Instance.CurrentGold}");

