// The issue: OnTowerSelected is called but _currentSlot might be null
// because when we click slot, HideAllPanels() is called first which sets _currentSlot to null!

// Let me trace through the exact flow:
// 1. OnMouseDown → HideAllPanels() → ShowTowerSelectPanel()
// 2. HideAllPanels hides the TowerSelectPanel, which calls Hide(), setting _currentSlot = null
// 3. Then ShowTowerSelectPanel shows it again, but _currentSlot was just cleared!

var tspObj = UnityEngine.GameObject.Find("画布/塔选择面板");
var tsp = tspObj.GetComponent<TowerDefense.UI.TowerSelectPanel>();

// Check _currentSlot via reflection
var currentSlotField = tsp.GetType().GetField("_currentSlot", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
var currentSlot = currentSlotField?.GetValue(tsp) as TowerDefense.Tower.TowerSlot;
UnityEngine.Debug.Log($"_currentSlot is: {(currentSlot != null ? currentSlot.gameObject.name : "NULL")}");

// Now click a fresh slot and immediately check
var slots = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.TowerSlot>();
var freshSlot = slots.FirstOrDefault(s => !s.IsOccupied);
if (freshSlot != null)
{
    // Click the slot
    freshSlot.GetType().GetMethod("OnMouseDown", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance)?.Invoke(freshSlot, null);

    // Immediately check _currentSlot
    currentSlot = currentSlotField?.GetValue(tsp) as TowerDefense.Tower.TowerSlot;
    UnityEngine.Debug.Log($"After click, _currentSlot is: {(currentSlot != null ? currentSlot.gameObject.name : "NULL")}");
}

